		function DefaultCurrency42() {}
		DefaultCurrency42.dataBinding = "/ds/EnterVariableData/curr1";
		DefaultCurrency42.tabIndex = -1;
		DefaultCurrency42.maxLength = 3;
		DefaultCurrency42.isReadOnly = function(){return true;}
		DefaultCurrency42.isTemporary = function(){return true;}
		DefaultCurrency42.transformToDisplay = function(value){
			return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
		DefaultCurrency42.transformToModel = function(value){
			return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
		InstalmentAmount.checkMaxValue = function( maxVal) { 
			var value = Services.getValue(InstalmentAmount.dataBinding);	      	      	
      		var err = validateCurrencyValue(value, maxVal, true);
      		if( err == null ) {  
      			Services.setValue(InstalmentAmount.dataBinding, WPU.formatToTwoDP(value)); }		   	  
	  		return err; }			
		InstalmentAmount.validateValueAmount = function() {	
		    var instVal = Services.getValue(InstalmentAmount.dataBinding);
		    var judgVal = Services.getValue(JudgmentAmount.dataBinding);
		    var costVal = Services.getValue(CostAmount.dataBinding);
		    var ppdVal  = Services.getValue(PrePaid.dataBinding);
		    var instAmnt = 0;
			var judgAmnt = 0;
			var costAmnt = 0;
			var ppdAmnt = 0;
			if( null != instVal && "" != instVal ) instAmnt = parseFloat(instVal);
			if( null != judgVal && "" != judgVal ) judgAmnt = parseFloat(judgVal);
			if( null != costVal && "" != costVal ) costAmnt = parseFloat(costVal);
			if( null != ppdVal && "" != ppdVal ) ppdAmnt = parseFloat(ppdVal);
			var err = null;
			if(Float.greaterThan(instAmnt,(judgAmnt + costAmnt ) - ppdAmnt)) {
				err = ErrorCode.getErrorCode("CaseMan_instalment_exceeds_total"); }																
			return err; }

